def f(expr):
    def compute(operands, operators):
        b = operands.pop()
        a = operands.pop()
        op = operators.pop()
        if op == '+':
            operands.append(a + b)
        elif op == '-':
            operands.append(a - b)
        elif op == '*':
            operands.append(a * b)

    def precedence(op):
        if op in ('+', '-'):
            return 1
        if op in ('*',):
            return 2
        return 0

    operands = []
    operators = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c == ' ':
            i += 1
            continue
        if c.isdigit():
            num = 0
            while i < n and expr[i].isdigit():
                num = num * 10 + int(expr[i])
                i += 1
            operands.append(num)
            continue
        if c == '(':
            operators.append(c)
        elif c == ')':
            while operators[-1] != '(':
                compute(operands, operators)
            operators.pop()
        else:
            while (operators and operators[-1] != '(' and
                   precedence(operators[-1]) >= precedence(c)):
                compute(operands, operators)
            operators.append(c)
        i += 1

    while operators:
        compute(operands, operators)

    return operands[-1]
